        const r = parseFloat(c.getAttribute("r")) || 0;
        const el = document.createElementNS("http://www.w3.org/2000/svg", "ellipse");
        el.setAttribute("cx", c.getAttribute("cx") || "0");
        el.setAttribute("cy", c.getAttribute("cy") || "0");
