      const _genres = (d.genres || []).map((g) => this._escHtml(g.name || "")).filter(Boolean).join(" \xB7 ");
      const _rating = d.voteAverage ? d.voteAverage.toFixed(1) : "";
      const _overview = this._escHtml(d.overview || "");
