      const alpha = typeof opacityPct === "number" && opacityPct >= 0 && opacityPct <= 100 ? opacityPct / 100 : 0.9;
      const v = hexRgba(userStyles.cardBackground, alpha);
      if (v) customVars.push(`--card-bg-perf: ${v}`);
